import { useEffect, useState } from 'react';
import { Alert, Button, Card, Col, Form, Row } from 'react-bootstrap';
import api from '../api/client';

const initialForm = {
  module: '', submodule: '', subject: '', description: '', user_id_value: '', user_password: '',
  reported_to: '', priority: 'Medium', support_decision: 'Solved by Support', email_config: '',
  support_remark: '', attachment_files: []
};

export default function TicketForm() {
  const [form, setForm] = useState(initialForm);
  const [modules, setModules] = useState([]);
  const [submodules, setSubmodules] = useState([]);
  const [reportedTo, setReportedTo] = useState([]);
  const [emailConfigs, setEmailConfigs] = useState([]);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    const load = async () => {
      const [m, s, r, e] = await Promise.all([
        api.get('/masters/modules/'),
        api.get('/masters/submodules/'),
        api.get('/masters/reported-to/'),
        api.get('/masters/email-configs/'),
      ]);
      setModules(m.data.filter(x => x.is_active));
      setSubmodules(s.data.filter(x => x.is_active));
      setReportedTo(r.data.filter(x => x.is_active));
      setEmailConfigs(e.data.filter(x => x.is_active));
    };
    load();
  }, []);

  const filteredSubmodules = submodules.filter(s => String(s.module) === String(form.module));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage(''); setError('');
    try {
      const data = new FormData();
      Object.entries(form).forEach(([key, value]) => {
        if (key === 'attachment_files') {
          form.attachment_files.forEach(file => data.append('attachment_files', file));
        } else if (value !== '' && value !== null && value !== undefined) {
          data.append(key, value);
        }
      });
      const response = await api.post('/tickets/', data, { headers: { 'Content-Type': 'multipart/form-data' } });
      const ticketId = response.data.id;
      if (form.support_decision === 'Moved to Development') {
        await api.post(`/tickets/${ticketId}/send_to_developer/`, { email_config: form.email_config, support_remark: form.support_remark });
      } else {
        await api.post(`/tickets/${ticketId}/resolve_support/`, { support_remark: form.support_remark });
      }
      setMessage('Ticket created successfully.');
      setForm(initialForm);
    } catch (err) {
      setError(JSON.stringify(err?.response?.data || 'Failed to create ticket'));
    }
  };

  return (
    <Card>
      <Card.Body>
        <h4 className="mb-3">Create Ticket</h4>
        {message && <Alert variant="success">{message}</Alert>}
        {error && <Alert variant="danger">{error}</Alert>}
        <Form onSubmit={handleSubmit}>
          <Row className="g-3">
            <Col md={6}><Form.Label>Module</Form.Label><Form.Select required value={form.module} onChange={e => setForm({ ...form, module: e.target.value, submodule: '' })}><option value="">Select</option>{modules.map(m => <option key={m.id} value={m.id}>{m.module_name}</option>)}</Form.Select></Col>
            <Col md={6}><Form.Label>Submodule</Form.Label><Form.Select required value={form.submodule} onChange={e => setForm({ ...form, submodule: e.target.value })}><option value="">Select</option>{filteredSubmodules.map(s => <option key={s.id} value={s.id}>{s.submodule_name}</option>)}</Form.Select></Col>
            <Col md={6}><Form.Label>Subject</Form.Label><Form.Control required value={form.subject} onChange={e => setForm({ ...form, subject: e.target.value })} /></Col>
            <Col md={6}><Form.Label>Reported To</Form.Label><Form.Select required value={form.reported_to} onChange={e => setForm({ ...form, reported_to: e.target.value })}><option value="">Select</option>{reportedTo.map(r => <option key={r.id} value={r.id}>{r.person_name}</option>)}</Form.Select></Col>
            <Col md={12}><Form.Label>Description</Form.Label><Form.Control as="textarea" rows={4} required value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} /></Col>
            <Col md={6}><Form.Label>User ID</Form.Label><Form.Control required value={form.user_id_value} onChange={e => setForm({ ...form, user_id_value: e.target.value })} /></Col>
            <Col md={6}><Form.Label>Password</Form.Label><Form.Control required value={form.user_password} onChange={e => setForm({ ...form, user_password: e.target.value })} /></Col>
            <Col md={4}><Form.Label>Priority</Form.Label><Form.Select value={form.priority} onChange={e => setForm({ ...form, priority: e.target.value })}><option>Low</option><option>Medium</option><option>High</option><option>Critical</option></Form.Select></Col>
            <Col md={4}><Form.Label>Support Decision</Form.Label><Form.Select required value={form.support_decision} onChange={e => setForm({ ...form, support_decision: e.target.value })}><option>Solved by Support</option><option>Moved to Development</option></Form.Select></Col>
            <Col md={4}><Form.Label>Email Config</Form.Label><Form.Select disabled={form.support_decision !== 'Moved to Development'} value={form.email_config} onChange={e => setForm({ ...form, email_config: e.target.value })}><option value="">Select</option>{emailConfigs.map(ec => <option key={ec.id} value={ec.id}>{ec.config_name}</option>)}</Form.Select></Col>
            <Col md={12}><Form.Label>Support Remark</Form.Label><Form.Control as="textarea" rows={2} value={form.support_remark} onChange={e => setForm({ ...form, support_remark: e.target.value })} /></Col>
            <Col md={12}><Form.Label>Attachments</Form.Label><Form.Control type="file" multiple onChange={e => setForm({ ...form, attachment_files: Array.from(e.target.files) })} /></Col>
          </Row>
          <div className="mt-3"><Button type="submit">Submit Ticket</Button></div>
        </Form>
      </Card.Body>
    </Card>
  );
}
